BEGIN;
--
-- Create model Classroom
--
CREATE TABLE "student_management_classroom" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "grade" integer NOT NULL, "section" varchar(10) NOT NULL, "room_number" varchar(10) NOT NULL);
--
-- Create model CollectorNode
--
