--
-- Create model School
--
CREATE TABLE "student_management_school" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "name" varchar(255) NOT NULL UNIQUE, "slug" varchar(100) NOT NULL UNIQUE, "is_active" boolean NOT NULL);
