-- Create model Student
--
CREATE TABLE "student_management_student" ("id" bigint NOT NULL PRIMARY KEY GENERATED BY DEFAULT AS IDENTITY, "first_name" varchar(100) NOT NULL, "last_name" varchar(100) NOT NULL, "dob" date NOT NULL, "roll_number" integer NOT NULL, "is_fully_enrolled" boolean NOT NULL, "photo_url" varchar(200) NOT NULL, "gender" varchar(1) NOT NULL, "blood_group" varchar(5) NOT NULL, "rfid_uid" varchar(50) NOT NULL, "admission_number" varchar(50) NOT NULL, "is_active" boolean NOT NULL);
